});
```

ZOOM CLAMP (mouse wheel):
```ts
this.input.on('wheel', (_ptr: unknown, _objs: unknown, _dx: unknown, dy: number) => {
  const next = Phaser.Math.Clamp(cam.zoom - dy * 0.001, 0.5, 2.0);
  cam.setZoom(next);
  // After zoom change, re-clamp scroll manually (setBounds doesn't account for new zoom):
  this.updateCamera(heroX, heroY);
});
```

RESIZE HANDLING:
```ts
// In create():
this.scale.on(Phaser.Scale.Events.RESIZE, (_gameSize: Phaser.Structs.Size) => {
  this.applyZoom();              // recalc zoom
  this.updateCamera(heroX, heroY); // re-clamp so new viewport size doesn't expose void
});
private applyZoom(): void {
  // Keep N world-rows visible; clamp for tiny/huge screens
  const TARGET_ROWS_VISIBLE = 14;
  const zoom = Phaser.Math.Clamp(this.scale.height / (TARGET_ROWS_VISIBLE * CELL), 0.5, 2.0);
  this.cameras.main.setZoom(zoom);
}
// ALSO clean up listener on SHUTDOWN:
this.events.on(Phaser.Scenes.Events.SHUTDOWN, () => {
  this.scale.off(Phaser.Scale.Events.RESIZE, this.applyZoom, this);
});
```

