```ts
// Clients send intents via sendEvent(), NOT updateSharedState/updateMyState
client.sendEvent('intent', {
  type: 'moveTo',   wx: worldX, wy: worldY          // right-click
} as MoveIntent);
client.sendEvent('intent', {
  type: 'castAbility', abilityIdx: 1, wx: worldX, wy: worldY
} as CastIntent);
